def validate_research_need(need):
    # N1: C-TOTALITY: if need is not a dict, return may_enter False (never crash)
    if not isinstance(need, dict):
        return {"may_enter": False, "reason": "need must be a dict"}

    # N2: nec must be present and a dict else may_enter False
    if "nec" not in need or not isinstance(need["nec"], dict):
        return {"may_enter": False, "reason": "nec must be present and a dict"}

    nec = need["nec"]

    # N3: nec['validated'] must be exactly True else may_enter False
    if nec.get("validated") is not True:
        return {"may_enter": False, "reason": "nec['validated'] must be exactly True"}

    # N4: nec['alternative_causes'] must be a NON-EMPTY list
    alternative_causes = nec.get("alternative_causes")
    if not isinstance(alternative_causes, list) or len(alternative_causes) == 0:
        return {"may_enter": False, "reason": "nec['alternative_causes'] must be a non-empty list"}

    # N5: nec['observed_block_refs'] must be a non-empty list
    observed_block_refs = nec.get("observed_block_refs")
    if not isinstance(observed_block_refs, list) or len(observed_block_refs) == 0:
        return {"may_enter": False, "reason": "nec['observed_block_refs'] must be a non-empty list"}

    # N6: decision_to_support must be a non-empty string
    decision_to_support = need.get("decision_to_support")
    if not isinstance(decision_to_support, str) or len(decision_to_support) == 0:
        return {"may_enter": False, "reason": "decision_to_support must be a non-empty string"}

    # All validations passed
    return {"may_enter": True, "reason": "All validation rules satisfied"}
